import { writeFileSync, mkdtempSync } from 'fs';
import { tmpdir } from 'os';
import { join } from 'path';
import { describe, it, expect } from 'vitest';
import { loadState, initializeState, saveState } from '../state.js';

describe('loadState legacy proofStatus backfill', () => {
  function writeStateFile(stateOverrides) {
    const dir = mkdtempSync(join(tmpdir(), 'proof-mcp-legacy-'));
    const file = join(dir, 'state.json');
    const base = initializeState('test');
    saveState(base, file);
    // Re-write with legacy values
    const raw = JSON.parse(require('fs').readFileSync(file, 'utf-8'));
    Object.assign(raw, stateOverrides);
    writeFileSync(file, JSON.stringify(raw));
    return file;
  }

  it("maps proofStatus 'open' ŌåÆ 'planning'", () => {
    const file = writeStateFile({ proofStatus: 'open' });
    expect(loadState(file).proofStatus).toBe('planning');
  });

  it("maps proofStatus 'closed' ŌåÆ 'finish'", () => {
    const file = writeStateFile({ proofStatus: 'closed' });
    expect(loadState(file).proofStatus).toBe('finish');
  });

  it("maps proofStatus 'unopen' ŌåÆ 'planning'", () => {
    const file = writeStateFile({ proofStatus: 'unopen' });
    expect(loadState(file).proofStatus).toBe('planning');
  });
});
```

